import { AdminErrorPanel } from '@/components/admin/AdminErrorPanel'
import { Badge } from '@/components/ui/badge'
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table'
import { fetchAdminMembers, type AdminMemberItem } from '@/lib/api/admin-members'

export const dynamic = 'force-dynamic'

function formatDate(value?: string | null) {
    if (!value) {
        return '—'
    }

    return new Date(value).toLocaleDateString()
}

function roleTone(role: string) {
    return role === 'admin'
        ? 'bg-sky-100 text-sky-800 dark:bg-sky-900/40 dark:text-sky-300'
        : 'bg-muted text-muted-foreground'
}

export default async function AdminMembersPage() {
    let members: AdminMemberItem[] = []
    let loadFailed = false

    try {
        members = await fetchAdminMembers()
    } catch {
        loadFailed = true
    }

    return (
        <div className="space-y-8">
            <div className="space-y-2">
                <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-50">Members</h1>
                <p className="text-sm text-muted-foreground">
                    Read-only membership overview. This screen is intentionally privacy-safe and excludes raw session or network identifiers.
                </p>
            </div>

            {loadFailed ? (
                <AdminErrorPanel
                    title="Members are unavailable"
                    message="Member profiles could not be loaded from the backend. Please retry after checking the API and database connection."
                />
            ) : (
                <div className="rounded-md border border-gray-200 bg-white dark:border-gray-800 dark:bg-gray-950">
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Member</TableHead>
                                <TableHead>Role</TableHead>
                                <TableHead>Provider</TableHead>
                                <TableHead>Joined</TableHead>
                                <TableHead>Last Login</TableHead>
                                <TableHead className="text-right">Active Sessions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {members.length > 0 ? (
                                members.map((member) => (
                                    <TableRow key={member.id} data-testid="member-row">
                                        <TableCell>
                                            <div className="space-y-1">
                                                <p className="font-medium text-foreground">{member.displayName}</p>
                                                <p className="text-sm text-muted-foreground">{member.email}</p>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <Badge variant="secondary" className={roleTone(member.role)}>
                                                {member.role}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="capitalize">{member.provider}</TableCell>
                                        <TableCell>{formatDate(member.createdAt)}</TableCell>
                                        <TableCell>{formatDate(member.lastLoginAt)}</TableCell>
                                        <TableCell className="text-right">{member.activeSessionCount}</TableCell>
                                    </TableRow>
                                ))
                            ) : (
                                <TableRow>
                                    <TableCell colSpan={6} className="h-24 text-center">
                                        No members found.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </div>
            )}
        </div>
    )
}
